#include <bits/stdc++.h>
using namespace std;
int n,sum[1025];
string s;
void dfs(int l,int r){
    if(l!=r){
        dfs(l,l+r>>1);
        dfs((l+r>>1)+1,r);
    }
    if(sum[r]-sum[l-1]==0)
        cout<<'B';
    else if(sum[r]-sum[l-1]==r-l+1)
        cout<<'I';
    else
        cout<<'F';
}
int main(){
    cin>>n;
    cin>>s;
    s=" "+s;
    for(int i=1;i<=1<<n;i++)
        sum[i]=sum[i-1]+s[i]-'0';
    dfs(1,1<<n);
    return 0;
}
